#include <stdio.h>
#include <stdlib.h>
#define MAX 1000000
int S[MAX];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B, X, Y, Z, P, C, Q;
        scanf("%d %d %d %d %d %d %d %d", &A, &B, &X, &Y, &Z, &P, &C, &Q);
        S[1] = A;
        S[2] = B;
        for (int i = 3; i < P * P + 3; i++) {
            S[i] = (X * S[i-1] + Y * S[i-2] + Z) % P;
        }
        while (Q--) {
            long long L, R;
            scanf("%lld %lld", &L, &R);
            int count = 0;
            for (long long i = L; i <= R; i++) {
                if (S[i % (P * P)] == C) {
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

