import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int A = sc.nextInt();
            int B = sc.nextInt();
            int X = sc.nextInt();
            int Y = sc.nextInt();
            int Z = sc.nextInt();
            int P = sc.nextInt();
            int C = sc.nextInt();
            int Q = sc.nextInt();
            int[] S = new int[P * P + 3];
            S[1] = A;
            S[2] = B;
            for (int i = 3; i < P * P + 3; i++) {
                S[i] = (X * S[i-1] + Y * S[i-2] + Z) % P;
            }
            while (Q-- > 0) {
                long L = sc.nextLong();
                long R = sc.nextLong();
                int count = 0;
                for (long i = L; i <= R; i++) {
                    if (S[(int)(i % (P * P))] == C) {
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
}

