const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [A, B, X, Y, Z, P, C, Q] = readline().split(' ').map(Number);
    const S = new Array(P * P + 3).fill(0);
    S[1] = A;
    S[2] = B;
    for (let j = 3; j < P * P + 3; j++) {
        S[j] = (X * S[j-1] + Y * S[j-2] + Z) % P;
    }
    for (let j = 0; j < Q; j++) {
        const [L, R] = readline().split(' ').map(BigInt);
        let count = 0;
        for (let k = L; k <= R; k++) {
            if (S[Number(k) % (P * P)] === C) {
                count++;
            }
        }
        console.log(count);
    }
}
